```yaml
# docker-compose.yml - Container-level hardening
version: '3.8'
services:
  app:
    image: myapp:latest
    environment:
      - JAVA_OPTS=-XX:+UseContainerSupport -XX:MaxRAMPercentage=75.0 -Djava.security.egd=file:/dev/./urandom
      # Explicitly disable dangerous features at JVM level
      - JAVA_TOOL_OPTIONS=-Dcom.sun.management.jmxremote=false -Dspring.jmx.enabled=false
    security_opt:
      - no-new-privileges:true
    read_only: true
    tmpfs:
      - /tmp
    ports:
      - "8443:8443"
    # Do NOT expose management port externally
    networks:
      - internal
```

**Defense in Depth Layers**:

1. **JVM Level**: Disable JMX and debug agents before application starts
```java
System.setProperty("com.sun.management.jmxremote", "false");
System.setProperty("spring.jmx.enabled", "false");
```

2. **Application Level**: Global data binding restrictions and startup validation
```java
@InitBinder
public void setDisallowedFields(WebDataBinder dataBinder) {
    dataBinder.setDisallowedFields("class.*", "Class.*");
}
```

3. **Configuration Level**: Explicit disabling of all unnecessary endpoints
```properties
management.endpoints.enabled-by-default=false
management.endpoint.heapdump.enabled=false
```

4. **Network Level**: Management endpoints on separate port, localhost only
```properties
management.server.port=9090
management.server.address=127.0.0.1
```

**Additional Protections**:

- **Startup Validation**: Application fails to start if dangerous features are detected
- **Audit Logging**: All configuration changes and security events are logged
- **Container Hardening**: Read-only filesystem, no-new-privileges, isolated network
- **Principle of Least Privilege**: Only health/info endpoints publicly accessible
- **Security Headers**: CSP, HSTS, X-Frame-Options applied to all actuator responses
- **Error Suppression**: Stack traces and internal details never exposed to clients

Production Go servers frequently expose unnecessary features that create attack surfaces. Debug endpoints, verbose errors, and permissive configurations are common misconfigurations that attackers actively exploit.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"net/http/pprof"
	"os"
	"runtime"
	"runtime/debug"

	_ "github.com/lib/pq"
)

var db *sql.DB

func main() {
	var err error
	db, err = sql.Open("postgres", os.Getenv("DATABASE_URL"))
	if err != nil {
		log.Fatal(err)
	}

	// VULNERABLE: Debug/profiling endpoints exposed in production
	http.HandleFunc("/debug/pprof/", pprof.Index)
	http.HandleFunc("/debug/pprof/cmdline", pprof.Cmdline)
	http.HandleFunc("/debug/pprof/profile", pprof.Profile)
	http.HandleFunc("/debug/pprof/symbol", pprof.Symbol)
	http.HandleFunc("/debug/pprof/trace", pprof.Trace)

	// VULNERABLE: Status endpoint exposes internal details
	http.HandleFunc("/status", func(w http.ResponseWriter, r *http.Request) {
		var memStats runtime.MemStats
		runtime.ReadMemStats(&memStats)
		status := map[string]interface{}{
			"go_version":    runtime.Version(),
			"goroutines":    runtime.NumGoroutine(),
			"memory_alloc":  memStats.Alloc,
			"db_connection": os.Getenv("DATABASE_URL"), // Exposes credentials!
			"env_vars":      os.Environ(),               // Exposes all env vars!
		}
		json.NewEncoder(w).Encode(status)
	})

	// VULNERABLE: Verbose error handler
	http.HandleFunc("/api/user", func(w http.ResponseWriter, r *http.Request) {
		rows, err := db.Query("SELECT * FROM users WHERE id = $1", r.URL.Query().Get("id"))
		if err != nil {
			// Exposes stack trace and internal paths
			http.Error(w, fmt.Sprintf("Database error: %v\nStack: %s", err, debug.Stack()), 500)
			return
		}
		defer rows.Close()
	})

	// VULNERABLE: All HTTP methods allowed, no security headers
	log.Fatal(http.ListenAndServe(":8080", nil))
}
