import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class ActuatorSecurityConfig {

    @Bean
    public SecurityFilterChain actuatorSecurityFilterChain(HttpSecurity http) throws Exception {
        http
            .securityMatcher("/internal/actuator/**")
            .authorizeHttpRequests(authz -> authz
                // Health endpoint for load balancers (limited info)
                .requestMatchers("/internal/actuator/health").permitAll()
                // All other actuator endpoints require ACTUATOR_ADMIN role
                .requestMatchers("/internal/actuator/**").hasRole("ACTUATOR_ADMIN")
            )
            .httpBasic(basic -> basic.realmName("Actuator"));

        return http.build();
    }
}
