**Key Security Controls**:
- **Minimal exposure**: Only expose health, info, and metrics endpoints needed for monitoring
- **Separate management port**: Run actuator on internal-only port (9090) bound to localhost
- **Authentication required**: All sensitive endpoints require ACTUATOR_ADMIN role
- **Disabled dangerous endpoints**: shutdown, heapdump, env, threaddump are completely disabled

In production Kubernetes environments, you need defense in depth: application-level security, network policies, and proper secrets management. Here's a complete production-ready configuration.

**PRODUCTION PATTERN**:

```java
import org.springframework.boot.actuate.autoconfigure.security.servlet.EndpointRequest;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.Profile;
import org.springframework.core.annotation.Order;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.ReferrerPolicyHeaderWriter;

@Configuration
@EnableWebSecurity
public class ProductionActuatorSecurity {

    @Bean
    @Order(1)
    @Profile("production")
    public SecurityFilterChain actuatorSecurityFilterChain(HttpSecurity http) throws Exception {
        http
            .securityMatcher(EndpointRequest.toAnyEndpoint())
            .authorizeHttpRequests(authz -> authz
                // Liveness probe - no auth needed (Kubernetes health checks)
                .requestMatchers(EndpointRequest.to("health")).permitAll()
                // Prometheus metrics - internal network only via network policy
                .requestMatchers(EndpointRequest.to("prometheus", "metrics")).hasIpAddress("10.0.0.0/8")
                // Info endpoint - basic details only
                .requestMatchers(EndpointRequest.to("info")).permitAll()
                // All other actuator endpoints - require admin authentication
                .anyRequest().hasRole("ACTUATOR_ADMIN")
            )
            .sessionManagement(session -> session
                .sessionCreationPolicy(SessionCreationPolicy.STATELESS)
            )
            .httpBasic(basic -> basic
                .realmName("Actuator-Production")
            )
            .headers(headers -> headers
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives("default-src 'none'")
                )
                .referrerPolicy(referrer -> referrer
                    .policy(ReferrerPolicyHeaderWriter.ReferrerPolicy.NO_REFERRER)
                )
            )
            .csrf(csrf -> csrf.disable()); // Stateless API

        return http.build();
    }
}
```

