```java
import org.springframework.boot.actuate.audit.AuditEvent;
import org.springframework.boot.actuate.audit.listener.AuditApplicationEvent;
import org.springframework.context.event.EventListener;
import org.springframework.stereotype.Component;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.time.Instant;

@Component
public class ActuatorAuditLogger {

    private static final Logger auditLogger = LoggerFactory.getLogger("ACTUATOR_AUDIT");

    @EventListener
    public void onAuditEvent(AuditApplicationEvent event) {
        AuditEvent auditEvent = event.getAuditEvent();

        auditLogger.warn(
            "ACTUATOR_ACCESS timestamp={} principal={} type={} endpoint={} remote_ip={}",
            Instant.now(),
            auditEvent.getPrincipal(),
            auditEvent.getType(),
            auditEvent.getData().get("endpoint"),
            auditEvent.getData().get("remote_address")
        );

        // Alert on suspicious access patterns
        if (isHighRiskEndpoint(auditEvent)) {
            sendSecurityAlert(auditEvent);
        }
    }

    private boolean isHighRiskEndpoint(AuditEvent event) {
        String endpoint = String.valueOf(event.getData().get("endpoint"));
        return endpoint.contains("loggers") || 
               endpoint.contains("threaddump") ||
               event.getType().equals("AUTHORIZATION_FAILURE");
    }

    private void sendSecurityAlert(AuditEvent event) {
        // Send to SIEM or alerting system
        auditLogger.error(
            "SECURITY_ALERT: Suspicious actuator access detected - {}",
            event.toString()
        );
    }
}
